"use strict";(globalThis.webpackChunkwgpu_html_docs=globalThis.webpackChunkwgpu_html_docs||[]).push([[1978],{2519(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","href":"/wgpu-html/docs/","label":"Welcome","docId":"index","unlisted":false},{"type":"category","label":"Getting Started","collapsed":false,"items":[{"type":"link","href":"/wgpu-html/docs/getting-started/overview","label":"What is wgpu-html?","docId":"getting-started/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/getting-started/installation","label":"Installation","docId":"getting-started/installation","unlisted":false},{"type":"link","href":"/wgpu-html/docs/getting-started/quick-start","label":"Quick Start","docId":"getting-started/quick-start","unlisted":false}],"collapsible":true},{"type":"category","label":"HTML Markup","items":[{"type":"link","href":"/wgpu-html/docs/html/overview","label":"HTML Markup Language","docId":"html/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/html/element-index","label":"Element Index","docId":"html/element-index","unlisted":false},{"type":"link","href":"/wgpu-html/docs/html/elements","label":"Element Reference","docId":"html/elements","unlisted":false},{"type":"link","href":"/wgpu-html/docs/html/parsing","label":"HTML Parser Internals","docId":"html/parsing","unlisted":false},{"type":"link","href":"/wgpu-html/docs/html/dom-api","label":"DOM-style API","docId":"html/dom-api","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"CSS & Styling","items":[{"type":"link","href":"/wgpu-html/docs/css/overview","label":"CSS Overview","docId":"css/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/syntax","label":"CSS Syntax & Data Types","docId":"css/syntax","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/property-index","label":"CSS Property Index","docId":"css/property-index","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/selectors","label":"CSS Selectors","docId":"css/selectors","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/cascade","label":"Cascade & Inheritance","docId":"css/cascade","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/box-model","label":"Box Model","docId":"css/box-model","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/colors-backgrounds","label":"Colors & Backgrounds","docId":"css/colors-backgrounds","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/typography","label":"Typography & Text Properties","docId":"css/typography","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/flexbox","label":"Flexbox Layout","docId":"css/flexbox","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/grid","label":"CSS Grid Layout","docId":"css/grid","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/positioned","label":"Positioned Layout","docId":"css/positioned","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/overflow","label":"Overflow Properties","docId":"css/overflow","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/variables","label":"Custom Properties (CSS Variables)","docId":"css/variables","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/math-functions","label":"CSS Math Functions","docId":"css/math-functions","unlisted":false},{"type":"link","href":"/wgpu-html/docs/css/css-roadmap","label":"CSS Roadmap","docId":"css/css-roadmap","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Layout Engine","items":[{"type":"link","href":"/wgpu-html/docs/layout/overview","label":"Layout Engine Overview","docId":"layout/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/layout/block","label":"Block Flow Layout","docId":"layout/block","unlisted":false},{"type":"link","href":"/wgpu-html/docs/layout/flexbox","label":"Flexbox Layout","docId":"layout/flexbox","unlisted":false},{"type":"link","href":"/wgpu-html/docs/layout/grid","label":"CSS Grid Layout","docId":"layout/grid","unlisted":false},{"type":"link","href":"/wgpu-html/docs/layout/positioned","label":"Positioned Layout","docId":"layout/positioned","unlisted":false},{"type":"link","href":"/wgpu-html/docs/layout/inline","label":"Inline Formatting Context","docId":"layout/inline","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Text & Typography","items":[{"type":"link","href":"/wgpu-html/docs/text/overview","label":"Text Rendering Overview","docId":"text/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/text/fonts","label":"Font System","docId":"text/fonts","unlisted":false},{"type":"link","href":"/wgpu-html/docs/text/shaping","label":"Text Shaping","docId":"text/shaping","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Rendering","items":[{"type":"link","href":"/wgpu-html/docs/rendering/overview","label":"Rendering Pipeline Overview","docId":"rendering/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/rendering/pipelines","label":"GPU Pipelines","docId":"rendering/pipelines","unlisted":false},{"type":"link","href":"/wgpu-html/docs/rendering/painting","label":"Paint Translation","docId":"rendering/painting","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Interactivity","items":[{"type":"link","href":"/wgpu-html/docs/interactivity/overview","label":"Interactivity Overview","docId":"interactivity/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/interactivity/events","label":"Event System","docId":"interactivity/events","unlisted":false},{"type":"link","href":"/wgpu-html/docs/interactivity/focus-keyboard","label":"Focus + Keyboard","docId":"interactivity/focus-keyboard","unlisted":false},{"type":"link","href":"/wgpu-html/docs/interactivity/forms","label":"Form Controls","docId":"interactivity/forms","unlisted":false},{"type":"link","href":"/wgpu-html/docs/interactivity/text-selection","label":"Text Selection","docId":"interactivity/text-selection","unlisted":false},{"type":"link","href":"/wgpu-html/docs/interactivity/scrolling","label":"Scrolling","docId":"interactivity/scrolling","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Rust Integration","items":[{"type":"link","href":"/wgpu-html/docs/rust-integration/overview","label":"Rust Integration Overview","docId":"rust-integration/overview","unlisted":false},{"type":"link","href":"/wgpu-html/docs/rust-integration/integrating","label":"Integration Guide","docId":"rust-integration/integrating","unlisted":false},{"type":"link","href":"/wgpu-html/docs/rust-integration/winit-harness","label":"Winit Harness (WgpuHtmlWindow)","docId":"rust-integration/winit-harness","unlisted":false},{"type":"link","href":"/wgpu-html/docs/rust-integration/bevy-integration","label":"Bevy Integration","docId":"rust-integration/bevy-integration","unlisted":false},{"type":"link","href":"/wgpu-html/docs/rust-integration/egui-backend","label":"egui Backend","docId":"rust-integration/egui-backend","unlisted":false},{"type":"link","href":"/wgpu-html/docs/rust-integration/screenshots","label":"Screenshots","docId":"rust-integration/screenshots","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Component Framework","items":[{"type":"link","href":"/wgpu-html/docs/component-framework/","label":"Component Framework (wgpu-html-ui)","docId":"component-framework/index","unlisted":false},{"type":"link","href":"/wgpu-html/docs/component-framework/component-trait","label":"Component Trait","docId":"component-framework/component-trait","unlisted":false},{"type":"link","href":"/wgpu-html/docs/component-framework/el-dsl","label":"El Builder DSL","docId":"component-framework/el-dsl","unlisted":false},{"type":"link","href":"/wgpu-html/docs/component-framework/ctx","label":"Ctx Callback Factory","docId":"component-framework/ctx","unlisted":false},{"type":"link","href":"/wgpu-html/docs/component-framework/store","label":"Store \u2014 Reactive Shared State","docId":"component-framework/store","unlisted":false},{"type":"link","href":"/wgpu-html/docs/component-framework/rendering","label":"Component Rendering Model","docId":"component-framework/rendering","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","href":"/wgpu-html/docs/devtools","label":"Devtools","docId":"devtools","unlisted":false},{"type":"link","href":"/wgpu-html/docs/comparison-wgpu-html-vs-rmlui","label":"vs RmlUI Comparison","docId":"comparison-wgpu-html-vs-rmlui","unlisted":false},{"type":"link","href":"/wgpu-html/docs/status","label":"Implementation Status","docId":"status","unlisted":false}]},"docs":{"comparison-wgpu-html-vs-rmlui":{"id":"comparison-wgpu-html-vs-rmlui","title":"wgpu-html vs RmlUI","description":"Date: 2026-05-03","sidebar":"docs"},"component-framework/component-trait":{"id":"component-framework/component-trait","title":"Component Trait","description":"The Component trait defines the lifecycle and API of a component. It\'s the core of the Elm-architecture model.","sidebar":"docs"},"component-framework/ctx":{"id":"component-framework/ctx","title":"Ctx Callback Factory","description":"Ctx is the callback factory passed to Component::view(). It creates event handlers that send messages to the component\'s update loop.","sidebar":"docs"},"component-framework/el-dsl":{"id":"component-framework/el-dsl","title":"El Builder DSL","description":"The El builder provides chainable methods for constructing HTML element trees. Each builder method returns Self for ergonomic chaining.","sidebar":"docs"},"component-framework/index":{"id":"component-framework/index","title":"Component Framework (wgpu-html-ui)","description":"wgpu-html-ui is an Elm-architecture component framework for building interactive UI with wgpu-html. It provides state management, scoped CSS, render caching, and a builder DSL \u2014 all in Rust.","sidebar":"docs"},"component-framework/rendering":{"id":"component-framework/rendering","title":"Component Rendering Model","description":"The runtime (wgpu-html-ui::runtime) manages mounted components and selects one of three render paths per frame to minimize work.","sidebar":"docs"},"component-framework/store":{"id":"component-framework/store","title":"Store \u2014 Reactive Shared State","description":"Store wraps a value of type T behind Arc> with a listener list. Any number of components can share a clone of the same store. When the value is mutated, all subscribers are notified.","sidebar":"docs"},"css/box-model":{"id":"css/box-model","title":"Box Model","description":"wgpu-html implements the standard CSS box model with content, padding, border, and margin boxes. The box model affects layout geometry (spacing, sizing) and paint (background clipping, border rendering).","sidebar":"docs"},"css/cascade":{"id":"css/cascade","title":"Cascade & Inheritance","description":"The cascade is the algorithm that determines which CSS declarations apply to each element when multiple rules target the same property. wgpu-html implements CSS-Cascade-3 \xa76 with a 4-band cascade, selector specificity ordering, inline style overrides, CSS-wide keyword resolution, and property inheritance.","sidebar":"docs"},"css/colors-backgrounds":{"id":"css/colors-backgrounds","title":"Colors & Backgrounds","description":"wgpu-html supports a broad range of CSS color formats and background properties. Colors are parsed into a typed CssColor enum and resolved to [r, g, b, a] linear sRGB at paint time for GPU consumption.","sidebar":"docs"},"css/css-roadmap":{"id":"css/css-roadmap","title":"CSS Roadmap","description":"Date: 2026-05-07","sidebar":"docs"},"css/flexbox":{"id":"css/flexbox","title":"Flexbox Layout","description":"wgpu-html implements complete CSS Flexible Box Layout Module Level 1 with all major properties. The flex layout engine handles axis direction, wrapping, grow/shrink distribution, alignment, gap, and ordering.","sidebar":"docs"},"css/grid":{"id":"css/grid","title":"CSS Grid Layout","description":"wgpu-html implements a substantial subset of CSS Grid Layout Module Level 1. The grid system supports explicit track definitions with flexible fr units, implicit tracks, named line placement, spanning, auto-placement, and full alignment.","sidebar":"docs"},"css/math-functions":{"id":"css/math-functions","title":"CSS Math Functions","description":"wgpu-html implements a full CSS math expression parser and evaluator. All numeric CSS properties that accept lengths can use calc(), min(), max(), clamp(), and 18 trigonometric/mathematical functions. Math expressions are parsed into an AST, stored as part of CssLength, and evaluated at layout time in length.rs.","sidebar":"docs"},"css/overflow":{"id":"css/overflow","title":"Overflow Properties","description":"wgpu-html implements CSS overflow handling with per-axis independent clipping, rectangular scissor clips, rounded SDF (Signed Distance Field) clipping, and a clip stack with rectangle intersection for nested overflow containers.","sidebar":"docs"},"css/overview":{"id":"css/overview","title":"CSS Overview","description":"wgpu-html implements a full CSS property parsing and cascade pipeline designed to mirror real browser behaviour while targeting embedded Rust UI. The CSS engine lives primarily in the wgpu-html-parser (tokenization, selector parsing, declaration parsing) and wgpu-html-style (cascade resolution, inheritance, selector matching) crates.","sidebar":"docs"},"css/positioned":{"id":"css/positioned","title":"Positioned Layout","description":"wgpu-html implements CSS positioned layout with static, relative, absolute, and fixed positioning. The layout engine resolves containing blocks, applies offsets, and handles shrink-to-fit sizing for absolutely positioned elements.","sidebar":"docs"},"css/property-index":{"id":"css/property-index","title":"CSS Property Index","description":"This is the complete index of all supported CSS properties in wgpu-html, formatted as a property table. Columns:","sidebar":"docs"},"css/selectors":{"id":"css/selectors","title":"CSS Selectors","description":"Notefirst-child,nth-child(),is(),has(),scope,dir(),checked,enabled,optional,read-write,first-of-type,nth-of-type(), and :nth-last-child().","sidebar":"docs"},"css/syntax":{"id":"css/syntax","title":"CSS Syntax & Data Types","description":"wgpu-html parses CSS values into strongly-typed Rust enums and structs. This page documents the supported syntax for each value type.","sidebar":"docs"},"css/typography":{"id":"css/typography","title":"Typography & Text Properties","description":"wgpu-html uses cosmic-text (backed by HarfBuzz for shaping and rustybuzz for fallback) to shape and render text. The typography system supports font family fallback, weight/style selection, text transformation, decorations, alignment, and more.","sidebar":"docs"},"css/variables":{"id":"css/variables","title":"Custom Properties (CSS Variables)","description":"wgpu-html fully implements CSS custom properties (CSS variables) with --* declaration syntax, var() usage, inheritance, recursive substitution, cycle detection, and a programmatic API for runtime manipulation.","sidebar":"docs"},"devtools":{"id":"devtools","title":"Devtools","description":"The wgpu-html-devtools crate provides a visual inspector panel built with wgpu-html-ui components. It opens in a secondary OS window for inspecting the host tree.","sidebar":"docs"},"getting-started/installation":{"id":"getting-started/installation","title":"Installation","description":"Add to Cargo.toml","sidebar":"docs"},"getting-started/overview":{"id":"getting-started/overview","title":"What is wgpu-html?","description":"wgpu-html is a GPU-accelerated HTML/CSS rendering engine for Rust. It takes real HTML5 markup and CSS stylesheets, runs them through a full browser-style pipeline (parser \u2192 cascade \u2192 layout \u2192 paint \u2192 render), and draws the result on screen using wgpu \u2014 all without a web browser.","sidebar":"docs"},"getting-started/quick-start":{"id":"getting-started/quick-start","title":"Quick Start","description":"This guide walks you through getting \\"Hello World\\" rendered on screen with wgpu-html in a winit window.","sidebar":"docs"},"html/dom-api":{"id":"html/dom-api","title":"DOM-style API","description":"wgpu-html exposes a browser-inspired DOM API on the Tree and Node types. All query methods are synchronous and walk the in-memory tree.","sidebar":"docs"},"html/element-index":{"id":"html/element-index","title":"Element Index","description":"This page lists every HTML element type recognized by wgpu-html. Each element is parsed into a typed Rust struct with per-element attribute parsing. Unknown tags are silently dropped.","sidebar":"docs"},"html/elements":{"id":"html/elements","title":"Element Reference","description":"This page provides detailed documentation for element attribute parsing, global attributes, and the most significant element types in wgpu-html.","sidebar":"docs"},"html/overview":{"id":"html/overview","title":"HTML Markup Language","description":"wgpu-html uses standard HTML5 as its markup language. There is no custom markup, no template DSL, and no intermediate representation. You author plain HTML5 documents and the engine parses them directly into a typed DOM tree.","sidebar":"docs"},"html/parsing":{"id":"html/parsing","title":"HTML Parser Internals","description":"The wgpu-html parser converts raw HTML strings into typed Tree> structures. It operates in two phases: tokenization and tree building.","sidebar":"docs"},"index":{"id":"index","title":"Welcome to wgpu-html","description":"GPU-accelerated HTML/CSS renderer for Rust, built on wgpu.","sidebar":"docs"},"interactivity/events":{"id":"interactivity/events","title":"Event System","description":"The event system models W3C DOM events via composition (wgpu-html-events crate) and delivers them through callback slots on Node (wgpu-html-tree).","sidebar":"docs"},"interactivity/focus-keyboard":{"id":"interactivity/focus-keyboard","title":"Focus + Keyboard","description":"Focus management and keyboard event dispatch are built into the tree\'s dispatch layer (wgpu-html-tree::dispatch).","sidebar":"docs"},"interactivity/forms":{"id":"interactivity/forms","title":"Form Controls","description":"Form control editing is implemented in wgpu-html-tree::text_edit (252 lines) and driven by keyboard input dispatch.","sidebar":"docs"},"interactivity/overview":{"id":"interactivity/overview","title":"Interactivity Overview","description":"Interactivity in wgpu-html is driven by Tree::interactivity).","sidebar":"docs"},"interactivity/scrolling":{"id":"interactivity/scrolling","title":"Scrolling","description":"Scrolling is implemented in wgpu-html::scroll (413 lines) with support for viewport-level and per-element scrolling.","sidebar":"docs"},"interactivity/text-selection":{"id":"interactivity/text-selection","title":"Text Selection","description":"Text selection allows users to highlight document text by dragging, double-clicking, or triple-clicking. The selection state lives in InteractionState::selection.","sidebar":"docs"},"layout/block":{"id":"layout/block","title":"Block Flow Layout","description":"Block flow is the default formatting context. Every block-level element stacks vertically inside its parent\'s content box.","sidebar":"docs"},"layout/flexbox":{"id":"layout/flexbox","title":"Flexbox Layout","description":"The flex formatting context implements CSS Flexbox Level 1 (\xa79) at a high level of fidelity. display: flex (or inline-flex) dispatches into layoutflexchildren().","sidebar":"docs"},"layout/grid":{"id":"layout/grid","title":"CSS Grid Layout","description":"The grid formatting context implements CSS Grid Layout Level 1 (\xa76\u2013\xa711). display: grid dispatches into layoutgridchildren().","sidebar":"docs"},"layout/inline":{"id":"layout/inline","title":"Inline Formatting Context","description":"The inline formatting context handles mixed text and inline-block children. When a block-level element\'s children are all inline-level (display: inline or text nodes), the engine builds line boxes.","sidebar":"docs"},"layout/overview":{"id":"layout/overview","title":"Layout Engine Overview","description":"The layout engine (wgpu-html-layout) converts a fully-cascaded style tree into a LayoutBox tree \u2014 a positioned, sized, shaped representation of every element in physical pixels. The renderer consumes LayoutBox directly; it never re-resolves CSS.","sidebar":"docs"},"layout/positioned":{"id":"layout/positioned","title":"Positioned Layout","description":"Out-of-flow positioning handles position: absolute, fixed, and relative. The engine implements the CSS Positioned Layout Module Level 3.","sidebar":"docs"},"rendering/overview":{"id":"rendering/overview","title":"Rendering Pipeline Overview","description":"The renderer (wgpu-html-renderer) converts a DisplayList into GPU draw calls. It owns the wgpu device, surface, and three GPU pipelines.","sidebar":"docs"},"rendering/painting":{"id":"rendering/painting","title":"Paint Translation","description":"The paint stage (wgpu-html::paint) walks the LayoutBox tree depth-first and emits a backend-agnostic DisplayList. The renderer consumes the display list without any knowledge of CSS or layout.","sidebar":"docs"},"rendering/pipelines":{"id":"rendering/pipelines","title":"GPU Pipelines","description":"wgpu-html renders through three custom GPU pipelines, each with its own WGSL shader, instancing strategy, and bind group layout.","sidebar":"docs"},"rust-integration/bevy-integration":{"id":"rust-integration/bevy-integration","title":"Bevy Integration","description":"The wgpu-html-driver-bevy crate provides WgpuHtmlPlugin \u2014 a single fullscreen transparent HTML overlay for Bevy applications.","sidebar":"docs"},"rust-integration/egui-backend":{"id":"rust-integration/egui-backend","title":"egui Backend","description":"The wgpu-html-egui crate provides an alternative integration path for embedding wgpu-html content inside egui/eframe applications.","sidebar":"docs"},"rust-integration/integrating":{"id":"rust-integration/integrating","title":"Integration Guide","description":"This guide walks through embedding wgpu-html in a custom Rust application from scratch, with full control over the event loop.","sidebar":"docs"},"rust-integration/overview":{"id":"rust-integration/overview","title":"Rust Integration Overview","description":"The wgpu-html crate is the top-level facade. It re-exports all sub-crates and provides convenient pipeline functions so you only need one dependency.","sidebar":"docs"},"rust-integration/profiling":{"id":"rust-integration/profiling","title":"Profiling and Performance","description":"wgpu-html includes built-in timing instrumentation, a ring-buffer frame"},"rust-integration/screenshots":{"id":"rust-integration/screenshots","title":"Screenshots","description":"wgpu-html supports capturing rendered output to PNG files, both from the live surface and off-screen.","sidebar":"docs"},"rust-integration/winit-harness":{"id":"rust-integration/winit-harness","title":"Winit Harness (WgpuHtmlWindow)","description":"The wgpu-html-winit crate provides a batteries-included window harness. It handles window setup, input forwarding, focus management, scrolling, clipboard, and screenshots.","sidebar":"docs"},"status":{"id":"status","title":"Implementation Status","description":"Date: 2026-05-07","sidebar":"docs"},"text/fonts":{"id":"text/fonts","title":"Font System","description":"Fonts are per-document assets registered on Tree::fonts (FontRegistry). The wgpu-html-text crate consumes &FontRegistry to build its shaping-side database.","sidebar":"docs"},"text/overview":{"id":"text/overview","title":"Text Rendering Overview","description":"Text rendering in wgpu-html is handled by the wgpu-html-text crate, which owns the shaping pipeline, font database, and CPU-side glyph atlas.","sidebar":"docs"},"text/shaping":{"id":"text/shaping","title":"Text Shaping","description":"Text shaping converts a string + CSS font properties into positioned, atlas-packed glyphs. The pipeline lives in wgpu-html-text::shape.rs.","sidebar":"docs"}}}}')}}]);